package org.apache.commons.lang3.mutable;

/**
 * Interface describing arithmetic operations for byte mutables.
 */
public interface ByteArithmetic {

    byte add(byte current, byte operand);

    byte add(byte current, Number operand);

    byte subtract(byte current, byte operand);

    byte subtract(byte current, Number operand);

    byte increment(byte current);

    byte decrement(byte current);

    byte addAndGet(byte current, byte operand);

    byte addAndGet(byte current, Number operand);

    byte getAndAdd(byte current, byte operand);

    byte getAndAdd(byte current, Number operand);

    byte incrementAndGet(byte current);

    byte getAndIncrement(byte current);

    byte decrementAndGet(byte current);

    byte getAndDecrement(byte current);
}

