package org.apache.commons.lang3.mutable;

import java.util.concurrent.atomic.AtomicInteger;

/**
 * A mutable {@code byte} wrapper.
 * <p>
 * This class was created before the introduction of the {@link java.util.concurrent.atomic} package and the {@link AtomicInteger} class.
 * </p>
 * <p>
 * Note that as MutableByte does not extend Byte, it is not treated by String.format as a Byte parameter.
 * </p>
 *
 * @see Byte
 * @see AtomicInteger
 * @since 2.1
 */
public class MutableByte extends Number implements Comparable<MutableByte>, Mutable<Number> {

    /**
     * Required for serialization support.
     *
     * @see java.io.Serializable
     */
    private static final long serialVersionUID = -1585823265L;

    private static final ByteArithmetic ARITH = new MutableByteArithmetic();

    /** The mutable value. */
    private byte value;

    /**
     * Constructs a new MutableByte with the default value of zero.
     */
    public MutableByte() {
    }

    /**
     * Constructs a new MutableByte with the specified value.
     *
     * @param value  the initial value to store
     */
    public MutableByte(final byte value) {
        this.value = value;
    }

    /**
     * Constructs a new MutableByte with the specified value.
     *
     * @param value  the initial value to store, not null.
     * @throws NullPointerException if the object is null.
     */
    public MutableByte(final Number value) {
        this.value = value.byteValue();
    }

    /**
     * Constructs a new MutableByte parsing the given string.
     *
     * @param value  the string to parse, not null.
     * @throws NumberFormatException if the string cannot be parsed into a byte, see {@link Byte#parseByte(String)}.
     * @since 2.5
     */
    public MutableByte(final String value) {
        this.value = Byte.parseByte(value);
    }

    /**
     * Adds a value to the value of this instance.
     *
     * @param operand  the value to add, not null.
     * @since 2.2
     */
    public void add(final byte operand) {
        this.value = ARITH.add(this.value, operand);
    }

    /**
     * Adds a value to the value of this instance.
     *
     * @param operand  the value to add, not null.
     * @throws NullPointerException if the object is null.
     * @since 2.2
     */
    public void add(final Number operand) {
        this.value = ARITH.add(this.value, operand);
    }

    /**
     * Increments this instance's value by {@code operand}; this method returns the value associated with the instance
     * immediately after the addition operation. This method is not thread safe.
     *
     * @param operand the quantity to add, not null.
     * @return the value associated with this instance after adding the operand.
     * @since 3.5
     */
    public byte addAndGet(final byte operand) {
        final byte newVal = ARITH.addAndGet(this.value, operand);
        this.value = newVal;
        return newVal;
    }

    /**
     * Increments this instance's value by {@code operand}; this method returns the value associated with the instance
     * immediately after the addition operation. This method is not thread safe.
     *
     * @param operand the quantity to add, not null.
     * @throws NullPointerException if {@code operand} is null.
     * @return the value associated with this instance after adding the operand.
     * @since 3.5
     */
    public byte addAndGet(final Number operand) {
        final byte newVal = ARITH.addAndGet(this.value, operand);
        this.value = newVal;
        return newVal;
    }

    // shortValue relies on Number implementation
    /**
     * Returns the value of this MutableByte as a byte.
     *
     * @return the numeric value represented by this object after conversion to type byte.
     */
    @Override
    public byte byteValue() {
        return value;
    }

    /**
     * Compares this mutable to another in ascending order.
     *
     * @param other  the other mutable to compare to, not null.
     * @return negative if this is less, zero if equal, positive if greater.
     */
    @Override
    public int compareTo(final MutableByte other) {
        return Byte.compare(this.value, other.value);
    }

    /**
     * Decrements the value.
     *
     * @since 2.2
     */
    public void decrement() {
        this.value = ARITH.decrement(this.value);
    }

    /**
     * Decrements this instance's value by 1; this method returns the value associated with the instance
     * immediately after the decrement operation. This method is not thread safe.
     *
     * @return the value associated with the instance after it is decremented.
     * @since 3.5
     */
    public byte decrementAndGet() {
        final byte newVal = ARITH.decrementAndGet(this.value);
        this.value = newVal;
        return newVal;
    }

    /**
     * Returns the value of this MutableByte as a double.
     *
     * @return the numeric value represented by this object after conversion to type double.
     */
    @Override
    public double doubleValue() {
        return value;
    }

    /**
     * Compares this object to the specified object. The result is {@code true} if and only if the argument is
     * not {@code null} and is a {@link MutableByte} object that contains the same {@code byte} value
     * as this object.
     *
     * @param obj  the object to compare with, null returns false.
     * @return {@code true} if the objects are the same; {@code false} otherwise.
     */
    @Override
    public boolean equals(final Object obj) {
        if (obj instanceof MutableByte) {
            return value == ((MutableByte) obj).byteValue();
        }
        return false;
    }

    /**
     * Returns the value of this MutableByte as a float.
     *
     * @return the numeric value represented by this object after conversion to type float.
     */
    @Override
    public float floatValue() {
        return value;
    }

    /**
     * Increments this instance's value by {@code operand}; this method returns the value associated with the instance
     * immediately prior to the addition operation. This method is not thread safe.
     *
     * @param operand the quantity to add, not null.
     * @return the value associated with this instance immediately before the operand was added.
     * @since 3.5
     */
    public byte getAndAdd(final byte operand) {
        final byte last = ARITH.getAndAdd(this.value, operand);
        this.value = ARITH.add(this.value, operand);
        return last;
    }

    /**
     * Increments this instance's value by {@code operand}; this method returns the value associated with the instance
     * immediately prior to the addition operation. This method is not thread safe.
     *
     * @param operand the quantity to add, not null.
     * @throws NullPointerException if {@code operand} is null.
     * @return the value associated with this instance immediately before the operand was added.
     * @since 3.5
     */
    public byte getAndAdd(final Number operand) {
        final byte last = ARITH.getAndAdd(this.value, operand);
        this.value = ARITH.add(this.value, operand);
        return last;
    }

    /**
     * Decrements this instance's value by 1; this method returns the value associated with the instance
     * immediately prior to the decrement operation. This method is not thread safe.
     *
     * @return the value associated with the instance before it was decremented.
     * @since 3.5
     */
    public byte getAndDecrement() {
        final byte last = ARITH.getAndDecrement(this.value);
        this.value = ARITH.decrement(this.value);
        return last;
    }

    /**
     * Increments this instance's value by 1; this method returns the value associated with the instance
     * immediately prior to the increment operation. This method is not thread safe.
     *
     * @return the value associated with the instance before it was incremented.
     * @since 3.5
     */
    public byte getAndIncrement() {
        final byte last = ARITH.getAndIncrement(this.value);
        this.value = ARITH.increment(this.value);
        return last;
    }

    /**
     * Gets the value as a Byte instance.
     *
     * @return the value as a Byte, never null.
     * @deprecated Use {@link #get()}.
     */
    @Deprecated
    @Override
    public Byte getValue() {
        return Byte.valueOf(this.value);
    }

    /**
     * Returns a suitable hash code for this mutable.
     *
     * @return a suitable hash code.
     */
    @Override
    public int hashCode() {
        return value;
    }

    /**
     * Increments the value.
     *
     * @since 2.2
     */
    public void increment() {
        this.value = ARITH.increment(this.value);
    }

    /**
     * Increments this instance's value by 1; this method returns the value associated with the instance
     * immediately after the increment operation. This method is not thread safe.
     *
     * @return the value associated with the instance after it is incremented.
     * @since 3.5
     */
    public byte incrementAndGet() {
        final byte newVal = ARITH.incrementAndGet(this.value);
        this.value = newVal;
        return newVal;
    }

    /**
     * Returns the value of this MutableByte as an int.
     *
     * @return the numeric value represented by this object after conversion to type int.
     */
    @Override
    public int intValue() {
        return value;
    }

    /**
     * Returns the value of this MutableByte as a long.
     *
     * @return the numeric value represented by this object after conversion to type long.
     */
    @Override
    public long longValue() {
        return value;
    }

    /**
     * Sets the value.
     *
     * @param value  the value to set.
     */
    public void setValue(final byte value) {
        this.value = value;
    }

    /**
     * Sets the value from any Number instance.
     *
     * @param value  the value to set, not null.
     * @throws NullPointerException if the object is null.
     */
    @Override
    public void setValue(final Number value) {
        this.value = value.byteValue();
    }

    /**
     * Subtracts a value from the value of this instance.
     *
     * @param operand  the value to subtract, not null.
     * @since 2.2
     */
    public void subtract(final byte operand) {
        this.value = ARITH.subtract(this.value, operand);
    }

    /**
     * Subtracts a value from the value of this instance.
     *
     * @param operand  the value to subtract, not null.
     * @throws NullPointerException if the object is null.
     * @since 2.2
     */
    public void subtract(final Number operand) {
        this.value = ARITH.subtract(this.value, operand);
    }

    /**
     * Gets this mutable as an instance of Byte.
     *
     * @return a Byte instance containing the value from this mutable.
     */
    public Byte toByte() {
        return Byte.valueOf(byteValue());
    }

    /**
     * Returns the String value of this mutable.
     *
     * @return the mutable value as a string.
     */
    @Override
    public String toString() {
        return String.valueOf(value);
    }

}

package org.apache.commons.lang3.mutable;

/**
 * Helper class that implements byte arithmetic operations used by {@link MutableByte}.
 *
 * <p>All methods are available as static helpers for backwards compatibility and as
 * instance methods via {@link ByteArithmetic} for dependency inversion.</p>
 */
public class MutableByteArithmetic implements ByteArithmetic {

    public MutableByteArithmetic() {
        // allow instantiation for interface-based usage
    }

    public static byte add(byte current, byte operand) {
        return (byte) (current + operand);
    }

    public static byte add(byte current, Number operand) {
        return add(current, operand.byteValue());
    }

    public static byte subtract(byte current, byte operand) {
        return (byte) (current - operand);
    }

    public static byte subtract(byte current, Number operand) {
        return subtract(current, operand.byteValue());
    }

    public static byte increment(byte current) {
        return add(current, (byte) 1);
    }

    public static byte decrement(byte current) {
        return subtract(current, (byte) 1);
    }

    public static byte addAndGet(byte current, byte operand) {
        return add(current, operand);
    }

    public static byte addAndGet(byte current, Number operand) {
        return add(current, operand);
    }

    public static byte getAndAdd(byte current, byte operand) {
        return current;
    }

    public static byte getAndAdd(byte current, Number operand) {
        return current;
    }

    public static byte incrementAndGet(byte current) {
        return increment(current);
    }

    public static byte getAndIncrement(byte current) {
        return current;
    }

    public static byte decrementAndGet(byte current) {
        return decrement(current);
    }

    public static byte getAndDecrement(byte current) {
        return current;
    }

    /* Instance implementations delegating to static helpers */

    @Override
    public byte add(byte current, byte operand) {
        return MutableByteArithmetic.add(current, operand);
    }

    @Override
    public byte add(byte current, Number operand) {
        return MutableByteArithmetic.add(current, operand);
    }

    @Override
    public byte subtract(byte current, byte operand) {
        return MutableByteArithmetic.subtract(current, operand);
    }

    @Override
    public byte subtract(byte current, Number operand) {
        return MutableByteArithmetic.subtract(current, operand);
    }

    @Override
    public byte increment(byte current) {
        return MutableByteArithmetic.increment(current);
    }

    @Override
    public byte decrement(byte current) {
        return MutableByteArithmetic.decrement(current);
    }

    @Override
    public byte addAndGet(byte current, byte operand) {
        return MutableByteArithmetic.addAndGet(current, operand);
    }

    @Override
    public byte addAndGet(byte current, Number operand) {
        return MutableByteArithmetic.addAndGet(current, operand);
    }

    @Override
    public byte getAndAdd(byte current, byte operand) {
        return MutableByteArithmetic.getAndAdd(current, operand);
    }

    @Override
    public byte getAndAdd(byte current, Number operand) {
        return MutableByteArithmetic.getAndAdd(current, operand);
    }

    @Override
    public byte incrementAndGet(byte current) {
        return MutableByteArithmetic.incrementAndGet(current);
    }

    @Override
    public byte getAndIncrement(byte current) {
        return MutableByteArithmetic.getAndIncrement(current);
    }

    @Override
    public byte decrementAndGet(byte current) {
        return MutableByteArithmetic.decrementAndGet(current);
    }

    @Override
    public byte getAndDecrement(byte current) {
        return MutableByteArithmetic.getAndDecrement(current);
    }
}

